            testHarness.processElement(new StreamRecord<>(new Tuple2<>("key1", 1), 10));
            testHarness.processElement(new StreamRecord<>(new Tuple2<>("key1", 2), 1000));
            testHarness.processElement(new StreamRecord<>(new Tuple2<>("key1", 33), 2500));

