    void testCleanupTimerWithEmptyListStateForTumblingWindows2(boolean enableAsyncState)
            throws Exception {
        final int windowSize = 2;
        final long lateness = 100;

        ListStateDescriptor<Tuple2<String, Integer>> windowStateDesc =
