    @Test
    void testSessionWindowsWithContinuousEventTimeTrigger() throws Exception {
        closeCalled.set(0);

        final int sessionSize = 3;

        ListStateDescriptor<Tuple2<String, Integer>> stateDesc =
                new ListStateDescriptor<>(
                        "window-contents",
