            operator =
                    new WindowOperatorFactory<>(
                            EventTimeSessionWindows.withGap(Duration.ofSeconds(gapSize)),
                            new TimeWindow.Serializer(),
                            new TupleKeySelector(),
                            BasicTypeInfo.STRING_TYPE_INFO.createSerializer(
                                    new SerializerConfigImpl()),
                            stateDesc,
                            new InternalSingleValueWindowFunction<>(
                                    new ReducedSessionWindowFunction()),
                            EventTimeTrigger.create(),
                            lateness,
                            lateOutputTag);

    OneInputStreamOperatorTestHarness<Tuple2<String, Integer>, Tuple3<String, Long, Long>>
            testHarness = createTestHarness(operator);

    testHarness.open();

    ConcurrentLinkedQueue<Object> expected = new ConcurrentLinkedQueue<>();
    ConcurrentLinkedQueue<Object> sideExpected = new ConcurrentLinkedQueue<>();

    // Create first session window [1000, 1003]
    testHarness.processElement(new StreamRecord<>(new Tuple2<>("key1", 1), 1000));
    testHarness.processWatermark(new Watermark(1001));
    expected.add(new Watermark(1001));

    // Advance watermark to make the window late
    // Window [1000, 1003] is late when: 1003 <= watermark (so at 1004)
    // Cleanup is at: 1003 + 10 = 1013 (window stays in-flight)
    testHarness.processWatermark(new Watermark(1005));
    expected.add(new Watermark(1005));

    // Send an element that extends the existing window
    // Creates window [999, 1002] which merges with [1000, 1003] -> [999, 1003]
    // Merged window [999, 1003] is late: (1003 <= 1005) = true
    // Before fix: window would be marked late and retired without processing element
    // After fix: since merging occurred, element is added to merged window
    testHarness.processElement(new StreamRecord<>(new Tuple2<>("key1", 1), 999));

    // Advance watermark to trigger the window (past window end)
    testHarness.processWatermark(new Watermark(1020));

    // The merged window [999, 1003] should fire with the sum of both elements (2)
    // This proves the late element was processed and added to the window
    expected.add(new StreamRecord<>(new Tuple3<>("key1-2", 999L, 1003L), 1002));
    expected.add(new Watermark(1020));

    TestHarnessUtil.assertOutputEqualsSorted(
            "Output was not correct.", expected, testHarness.getOutput(), new Tuple2ResultSortComparator());
    TestHarnessUtil.assertOutputEqualsSorted(
            "SideOutput was not correct (should be empty since element was merged, not late-dropped).",
            sideExpected,
            (Iterable) testHarness.getSideOutput(lateOutputTag),
            new Tuple2ResultSortComparator());
    testHarness.close();
}

